const normalizeTeamName = (name: string) =>
  name
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/mammoths/gi, "mammoth")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " " )
    .trim();

export const findNhlTeamCatalog = (teamName: string) =>
  NHL_CATALOG.find((team) => normalizeTeamName(team.teamName) === normalizeTeamName(teamName) || normalizeTeamName(team.shopTeamName) === normalizeTeamName(teamName));
